#!/usr/bin/env node
/**
 * Concatenates the individual popup dist scripts into a single bundle so
 * popup.html only has to load/parse one <script> instead of a dozen.
 *
 * These files are plain classic scripts (no import/export) that already rely
 * on sharing one global scope via document order - see the "Shared globals
 * for classic <script> tags" comment in eslint.config.mjs - so concatenation
 * in the same order is behaviorally identical to the separate <script> tags.
 *
 * The individual source files remain the source of truth (they're what
 * Jest/eslint/prettier operate on); this script only regenerates the
 * generated bundle consumed by popup.html. Re-run after editing any of the
 * files listed below.
 */
const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const DIST_DIR = path.join(ROOT, "Package", "dist");
const OUTPUT_FILE = path.join(DIST_DIR, "popup.bundle.js");

// Order matters: it must match the original <script defer> order in
// popup.html, since later files reference globals declared by earlier ones.
const SOURCE_FILES = [
  "utils/dom.js",
  "hooks/popupState.js",
  "utils/theme.js",
  "components/menu.js",
  "components/remove.js",
  "components/favorite.js",
  "components/history.js",
  "components/gemini.js",
  "components/modal.js",
  "components/onboarding.js",
  "utils/payment.js",
  "popup.js",
];

function buildBundle() {
  const banner = `/**
 * AUTO-GENERATED FILE - do not edit directly.
 * Generated by scripts/build-popup-bundle.js from the individual files
 * listed there. Edit the source files and run \`npm run build:popup\`
 * (or \`npm run build\`) to regenerate this bundle.
 */
`;

  const sections = SOURCE_FILES.map((relativePath) => {
    const absolutePath = path.join(DIST_DIR, relativePath);
    const content = fs.readFileSync(absolutePath, "utf8");
    return `// ---- ${relativePath.replace(/\\/g, "/")} ----\n${content}`;
  });

  const output = banner + "\n" + sections.join("\n");
  fs.writeFileSync(OUTPUT_FILE, output);
  console.log(`Wrote ${path.relative(ROOT, OUTPUT_FILE)} (${SOURCE_FILES.length} files bundled)`);
}

buildBundle();
